CREATE TABLE roles (id BIGSERIAL PRIMARY KEY, nombre VARCHAR(30) NOT NULL UNIQUE);
CREATE TABLE entidades_financieras (id BIGSERIAL PRIMARY KEY, ruc VARCHAR(11) NOT NULL UNIQUE, razon_social VARCHAR(150) NOT NULL, contacto VARCHAR(150), email VARCHAR(150), activo BOOLEAN NOT NULL DEFAULT TRUE, creado_en TIMESTAMPTZ NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE usuarios (id BIGSERIAL PRIMARY KEY, nombre_completo VARCHAR(150) NOT NULL, email VARCHAR(150) NOT NULL UNIQUE, password_hash VARCHAR(100) NOT NULL, rol_id BIGINT NOT NULL REFERENCES roles(id), entidad_id BIGINT REFERENCES entidades_financieras(id), activo BOOLEAN NOT NULL DEFAULT TRUE, creado_en TIMESTAMPTZ NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE analistas (id BIGSERIAL PRIMARY KEY, usuario_id BIGINT NOT NULL UNIQUE REFERENCES usuarios(id), codigo VARCHAR(30) NOT NULL UNIQUE, disponible BOOLEAN NOT NULL DEFAULT TRUE);
CREATE TABLE protestos (id BIGSERIAL PRIMARY KEY, entidad_id BIGINT NOT NULL REFERENCES entidades_financieras(id), numero_documento VARCHAR(20) NOT NULL, nombre_deudor VARCHAR(150) NOT NULL, tipo_titulo VARCHAR(50) NOT NULL, monto NUMERIC(14,2) NOT NULL, moneda VARCHAR(3) NOT NULL, fecha_protesto DATE NOT NULL, vigente BOOLEAN NOT NULL DEFAULT TRUE);
CREATE TABLE solicitudes (id BIGSERIAL PRIMARY KEY, codigo VARCHAR(30) NOT NULL UNIQUE, solicitante_id BIGINT NOT NULL REFERENCES usuarios(id), entidad_id BIGINT NOT NULL REFERENCES entidades_financieras(id), analista_id BIGINT REFERENCES analistas(id), estado VARCHAR(30) NOT NULL, motivo VARCHAR(1000) NOT NULL, observacion VARCHAR(1000), creado_en TIMESTAMPTZ NOT NULL DEFAULT CURRENT_TIMESTAMP, actualizado_en TIMESTAMPTZ NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE documentos (id BIGSERIAL PRIMARY KEY, solicitud_id BIGINT NOT NULL REFERENCES solicitudes(id), nombre_original VARCHAR(255) NOT NULL, nombre_almacenado VARCHAR(255) NOT NULL, tipo_contenido VARCHAR(100) NOT NULL, tamano BIGINT NOT NULL, creado_en TIMESTAMPTZ NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE cargas_excel (id BIGSERIAL PRIMARY KEY, usuario_id BIGINT NOT NULL REFERENCES usuarios(id), nombre_archivo VARCHAR(255) NOT NULL, estado VARCHAR(30) NOT NULL, resumen VARCHAR(500), creado_en TIMESTAMPTZ NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE auditoria (id BIGSERIAL PRIMARY KEY, actor VARCHAR(150) NOT NULL, accion VARCHAR(80) NOT NULL, recurso VARCHAR(80) NOT NULL, recurso_id VARCHAR(80), detalle VARCHAR(500), fecha TIMESTAMPTZ NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE INDEX idx_solicitudes_solicitante ON solicitudes(solicitante_id);
CREATE INDEX idx_solicitudes_estado ON solicitudes(estado);
CREATE INDEX idx_protestos_documento ON protestos(numero_documento);
CREATE INDEX idx_auditoria_fecha ON auditoria(fecha DESC);
